import React, { useState } from 'react'
import { AMT_CONFIRM_BTN_TEXT, AMT_PLACEHOLDER } from '../constants'
import useSplitPaymentStore from '../useSplitPaymentStore'
function TotalAmount() {
    const [inputVal, setInputVal] = useState(0)
    const setTotalAmount = useSplitPaymentStore((s) => s.setTotalAmount)

    return (<div>
        <div className='bg-white'><input style={{ all: 'unset' }} value={inputVal} type='text' placeholder={AMT_PLACEHOLDER} onChange={(e) => setInputVal(e.target.value)} /></div>
        <button onClick={() => setTotalAmount(inputVal)}>{AMT_CONFIRM_BTN_TEXT}</button>
    </div>)
}

export default TotalAmount
